import mongoose, { Schema, Document } from "mongoose";
import { Device, DeviceType, DeviceStatus } from "../types/index";

export interface DeviceDocument extends Device, Document {
  id: string;
  createdAt: Date;
  updatedAt: Date;
}

const deviceSchema = new Schema(
  {
    roomId: { type: String, required: true },
    name: { type: String, required: true },
    type: { type: String, enum: Object.values(DeviceType), required: true },
    status: { type: String, enum: Object.values(DeviceStatus), default: DeviceStatus.OFF },
    lastUpdate: { type: String, default: () => new Date().toISOString() },
    brightness: Number,
    color: String,
    temperature: Number,
    mode: String,
    locked: Boolean,
    readingType: String,
    value: Number,
  },
  {
    timestamps: true,
    toJSON: {
      transform: function (doc, ret: any) {
        ret.id = ret._id.toString();
        delete ret._id;
        delete ret.__v;
      },
    },
    toObject: {
      transform: function (doc, ret: any) {
        ret.id = ret._id.toString();
        delete ret._id;
        delete ret.__v;
      },
    },
  }
);

export const DeviceModel = mongoose.model<DeviceDocument>("Device", deviceSchema);
