
import { type NextRequest, NextResponse } from "next/server"
import { connectDB } from "@/src/lib/mongodb"
import { DeviceModel } from "@/src/models/Device"

export async function GET(request: NextRequest) {
  try {
    await connectDB()
    const devices = await DeviceModel.find({})
    return NextResponse.json({ devices })
  } catch (error) {
    console.error("Error fetching devices:", error)
    return NextResponse.json({ error: "Failed to fetch devices" }, { status: 500 })
  }
}

export async function POST(request: NextRequest) {
  try {
    await connectDB()
    const body = await request.json()
    const device = await DeviceModel.create(body)
    return NextResponse.json(device, { status: 201 })
  } catch (error) {
    console.error("Error creating device:", error)
    return NextResponse.json({ error: "Failed to create device" }, { status: 500 })
  }
}

export async function PUT(request: NextRequest) {
  try {
    await connectDB()
    const { searchParams } = new URL(request.url)
    const id = searchParams.get('id')
    const body = await request.json()
    const updatedDevice = await DeviceModel.findByIdAndUpdate(id, body, { new: true })
    if (!updatedDevice) {
      return NextResponse.json({ error: "Device not found" }, { status: 404 })
    }
    return NextResponse.json(updatedDevice)
  } catch (error) {
    console.error("Error updating device:", error)
    return NextResponse.json({ error: "Failed to update device" }, { status: 500 })
  }
}

export async function DELETE(request: NextRequest) {
  try {
    await connectDB()
    const { searchParams } = new URL(request.url)
    const id = searchParams.get('id')
    const deletedDevice = await DeviceModel.findByIdAndDelete(id)
    if (!deletedDevice) {
      return NextResponse.json({ error: "Device not found" }, { status: 404 })
    }
    return NextResponse.json({ message: "Device deleted successfully" })
  } catch (error) {
    console.error("Error deleting device:", error)
    return NextResponse.json({ error: "Failed to delete device" }, { status: 500 })
  }
}
